using System.ComponentModel;
using System.Text;
using System.Text.Json;
using System.Web;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Configuration ────────────────────────────────────────────────────────────

var topic = args.Length > 0
    ? string.Join(" ", args)
    : PromptForInput("Enter a research topic");

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Please set the OPENAI_API_KEY environment variable.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o";

Console.WriteLine();
Console.WriteLine($"🔍 Researching: {topic}");
Console.WriteLine($"   Model: {model}");
Console.WriteLine(new string('─', 60));

// ── Shared state ─────────────────────────────────────────────────────────────

var notebook = new Notebook();
using var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");
httpClient.Timeout = TimeSpan.FromSeconds(15);

// ── Tools ────────────────────────────────────────────────────────────────────

var tools = new AITool[]
{
    AIFunctionFactory.Create(SearchWebAsync, "search_web",
        "Searches the web for information and returns relevant article snippets. " +
        "Use different queries to explore multiple angles of the topic."),

    AIFunctionFactory.Create(TakeNote, "take_note",
        "Saves a research note with a short title and detailed content. " +
        "Use this to record key findings as you research."),

    AIFunctionFactory.Create(GetNotes, "get_notes",
        "Retrieves all previously saved research notes."),
};

// ── Agent setup ──────────────────────────────────────────────────────────────

const string Instructions = """
    You are a thorough research agent. Your workflow is:
    1. Break the topic into 3-5 key aspects worth investigating.
    2. For each aspect, use the search_web tool to find information.
    3. After each search, use take_note to record the most important findings
       (facts, dates, figures, notable details).
    4. Once you have covered the topic broadly, use get_notes to review everything.
    5. Synthesize your notes into a well-structured, comprehensive summary with
       sections, key facts, and a brief conclusion.

    Be factual and cite specific details from your research. If a search returns
    limited results, try rephrasing the query or searching a related sub-topic.
    """;

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient();

var agent = chatClient.AsAIAgent(
    instructions: Instructions,
    name: "ResearchAgent",
    description: "An agent that researches topics using web search and note-taking.",
    tools: tools);

// ── Run the agent ────────────────────────────────────────────────────────────

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(
    $"Please research the following topic and provide a comprehensive summary: {topic}",
    session);

Console.WriteLine();
Console.WriteLine(new string('─', 60));
Console.WriteLine("📋 RESEARCH SUMMARY");
Console.WriteLine(new string('─', 60));
Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();

if (notebook.Count > 0)
{
    Console.WriteLine(new string('─', 60));
    Console.WriteLine($"📝 {notebook.Count} note(s) were taken during research.");
    Console.WriteLine(new string('─', 60));
}

// ── Tool implementations ─────────────────────────────────────────────────────

async Task<string> SearchWebAsync(
    [Description("The search query to look up")] string query)
{
    Console.WriteLine($"  🌐 Searching: \"{query}\"");

    try
    {
        // Use the Wikipedia API — free, no auth required, returns structured results
        var url = "https://en.wikipedia.org/w/api.php"
            + $"?action=query&list=search&srsearch={Uri.EscapeDataString(query)}"
            + "&format=json&srlimit=5&srprop=snippet|titlesnippet&utf8=1";

        var json = await httpClient.GetStringAsync(url);
        var doc = JsonDocument.Parse(json);
        var results = doc.RootElement
            .GetProperty("query")
            .GetProperty("search");

        if (results.GetArrayLength() == 0)
            return $"No results found for \"{query}\". Try a different query.";

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for \"{query}\":");
        sb.AppendLine();

        foreach (var item in results.EnumerateArray())
        {
            var title = item.GetProperty("title").GetString();
            var snippet = StripHtml(item.GetProperty("snippet").GetString() ?? "");
            sb.AppendLine($"• {title}");
            sb.AppendLine($"  {snippet}");
            sb.AppendLine();
        }

        Console.WriteLine($"    ✓ Found {results.GetArrayLength()} result(s)");
        return sb.ToString();
    }
    catch (Exception ex)
    {
        Console.WriteLine($"    ⚠ Search failed: {ex.Message}");
        return $"Search for \"{query}\" failed: {ex.Message}. Try a different query.";
    }
}

string TakeNote(
    [Description("A short title for the note")] string title,
    [Description("Detailed note content with key facts and findings")] string content)
{
    notebook.Add(title, content);
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    return $"Note \"{title}\" saved successfully ({notebook.Count} total notes).";
}

string GetNotes()
{
    var notes = notebook.GetAll();
    Console.WriteLine($"  📖 Retrieved {notes.Count} note(s)");

    if (notes.Count == 0)
        return "No notes have been saved yet. Use take_note to record findings.";

    var sb = new StringBuilder();
    sb.AppendLine($"All research notes ({notes.Count} total):");
    sb.AppendLine();

    for (int i = 0; i < notes.Count; i++)
    {
        sb.AppendLine($"── Note {i + 1}: {notes[i].Title} ──");
        sb.AppendLine(notes[i].Content);
        sb.AppendLine();
    }

    return sb.ToString();
}

// ── Helpers ──────────────────────────────────────────────────────────────────

static string PromptForInput(string prompt)
{
    Console.Write($"{prompt}: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? throw new InvalidOperationException("No topic provided.")
        : input;
}

static string StripHtml(string html)
{
    // Decode HTML entities and strip tags for clean display
    var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "");
    return HttpUtility.HtmlDecode(text);
}

// ── Notebook class ───────────────────────────────────────────────────────────

sealed class Notebook
{
    private readonly List<Note> _notes = [];
    private readonly Lock _lock = new();

    public int Count { get { lock (_lock) return _notes.Count; } }

    public void Add(string title, string content)
    {
        lock (_lock)
            _notes.Add(new Note(title, content));
    }

    public IReadOnlyList<Note> GetAll()
    {
        lock (_lock)
            return [.. _notes];
    }
}

record Note(string Title, string Content);

