 if (notebook.Count > 0)
 {
     Console.WriteLine(new string('─', 60));
     Console.WriteLine($"📝 {notebook.Count} note(s) were taken during research.");
     Console.WriteLine(new string('─', 60));
 }

 // ── Tool implementations ─────────────────────────────────────────────────────

 async Task<string> SearchWebAsync(
     [Description("The search query to look up")] string query)
 {
     Console.WriteLine($"  🌐 Searching: \"{query}\"");

     try
     {
         // Use the Wikipedia API — free, no auth required, returns structured results
         var url = "https://en.wikipedia.org/w/api.php"
             + $"?action=query&list=search&srsearch={Uri.EscapeDataString(query)}"
             + "&format=json&srlimit=5&srprop=snippet|titlesnippet&utf8=1";

         var json = await httpClient.GetStringAsync(url);
         var doc = JsonDocument.Parse(json);
         var results = doc.RootElement
             .GetProperty("query")
             .GetProperty("search");

         if (results.GetArrayLength() == 0)
             return $"No results found for \"{query}\". Try a different query.";

         var sb = new StringBuilder();
         sb.AppendLine($"Search results for \"{query}\":");
         sb.AppendLine();

         foreach (var item in results.EnumerateArray())
         {
             var title = item.GetProperty("title").GetString();
             var snippet = StripHtml(item.GetProperty("snippet").GetString() ?? "");
             sb.AppendLine($"• {title}");
             sb.AppendLine($"  {snippet}");
             sb.AppendLine();
         }

         Console.WriteLine($"    ✓ Found {results.GetArrayLength()} result(s)");
         return sb.ToString();
     }
     catch (Exception ex)
     {
         Console.WriteLine($"    ⚠ Search failed: {ex.Message}");
         return $"Search for \"{query}\" failed: {ex.Message}. Try a different query.";
     }
 }

 string TakeNote(
     [Description("A short title for the note")] string title,
     [Description("Detailed note content with key facts and findings")] string content)
 {
     notebook.Add(title, content);
     Console.WriteLine($"  📝 Note saved: \"{title}\"");
     return $"Note \"{title}\" saved successfully ({notebook.Count} total notes).";
 }

 string GetNotes()
 {
     var notes = notebook.GetAll();
     Console.WriteLine($"  📖 Retrieved {notes.Count} note(s)");

     if (notes.Count == 0)
         return "No notes have been saved yet. Use take_note to record findings.";

     var sb = new StringBuilder();
     sb.AppendLine($"All research notes ({notes.Count} total):");
     sb.AppendLine();

     for (int i = 0; i < notes.Count; i++)
     {
         sb.AppendLine($"── Note {i + 1}: {notes[i].Title} ──");
         sb.AppendLine(notes[i].Content);
         sb.AppendLine();
     }

     return sb.ToString();
 }

 // ── Helpers ──────────────────────────────────────────────────────────────────

 static string PromptForInput(string prompt)
 {
     Console.Write($"{prompt}: ");
     var input = Console.ReadLine()?.Trim();
     return string.IsNullOrEmpty(input)
         ? throw new InvalidOperationException("No topic provided.")
         : input;
 }

 static string StripHtml(string html)
 {
     // Decode HTML entities and strip tags for clean display
     var text = System.Text.RegularExpressions.Regex.Replace(html, "<[^>]+>", "");
     return HttpUtility.HtmlDecode(text);
 }

 // ── Notebook class ───────────────────────────────────────────────────────────

 sealed class Notebook
 {
     private readonly List<Note> _notes = [];
     private readonly Lock _lock = new();

     public int Count { get { lock (_lock) return _notes.Count; } }

     public void Add(string title, string content)
     {
         lock (_lock)
             _notes.Add(new Note(title, content));
     }

     public IReadOnlyList<Note> GetAll()
     {
         lock (_lock)
             return [.. _notes];
     }
 }

 record Note(string Title, string Content);

